# Concrete shape implementations
from shapes_base import ShapeBase, ShapeCategory, IDrawable, IMeasurable, IScalable

class Rectangle(ShapeBase, IDrawable, IMeasurable, IScalable):
    width: float
    height: float

    def __init__(self, w: float, h: float):
        super().__init__(ShapeCategory.PRIMITIVE)
        self.width = w
        self.height = h

    def draw(self) -> str:
        return f"Rectangle({self.width} x {self.height})"

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    @override
    def description(self) -> str:
        return f"Rectangle with area {self.area()}"

class Circle(ShapeBase, IDrawable, IMeasurable, IScalable):
    radius: float

    def __init__(self, r: float):
        super().__init__(ShapeCategory.PRIMITIVE)
        self.radius = r

    def draw(self) -> str:
        return f"Circle(r={self.radius})"

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

class ColoredRectangle(Rectangle):
    _color: str

    def __init__(self, w: float, h: float, c: str):
        super().__init__(w, h)
        self._color = c

    def get_color(self) -> str:
        return self._color

    @override
    def draw(self) -> str:
        return f"ColoredRectangle({self._color}, {self.width} x {self.height})"

