# Geometry utilities with struct and generic functions
struct Point:
    x: float
    y: float

    def __init__(self, x_coord: float, y_coord: float):
        self.x = x_coord
        self.y = y_coord

    def distance_from_origin(self) -> float:
        return pow(self.x * self.x + self.y * self.y, 0.5)
